import { Component, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { trigger, transition, style, animate } from '@angular/animations';
import { Subject } from 'rxjs';
import { takeUntil } from 'rxjs/operators';
import { ParkaddaService } from '../../../../services/parkadda.service';
import { ParkaddaAuthService } from '../../../../services/parkadda-auth.service';
import { ParkingLocation, ParkingOccupancy } from '../../../../models/parkadda.models';

@Component({
  selector: 'app-parking-list',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './parking-list.component.html',
  styleUrls: ['./parking-list.component.scss'],
  animations: [
    trigger('fadeInOut', [
      transition(':enter', [
        style({ opacity: 0, transform: 'translateY(-10px)' }),
        animate('300ms ease-in', style({ opacity: 1, transform: 'translateY(0)' }))
      ])
    ])
  ]
})
export class ParkingListComponent implements OnInit, OnDestroy {
  parkingLocations: ParkingLocation[] = [];
  filteredParkings: ParkingLocation[] = [];
  occupancyData: Map<number, ParkingOccupancy> = new Map();
  loading = false;
  error: string | null = null;
  searchTerm = '';
  selectedParkingId: number | null = null;
  selectedParking: ParkingLocation | null = null;
  isAuthenticated = false;
  showDetailsModal = false;
  canAdd = true;
  canEdit = true;
  canDelete = true;
  statusFilter = 'all';
  currentPage = 1;
  totalPages = 1;
  totalCount = 0;
  toasts: Array<{ message: string; type: string }> = [];

  private destroy$ = new Subject<void>();

  constructor(
    private parkaddaService: ParkaddaService,
    private authService: ParkaddaAuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.checkAuthentication();
    this.loadParkingLocations();
  }

  private checkAuthentication(): void {
    this.isAuthenticated = this.authService.isParkaddaAuthenticated();
    if (!this.isAuthenticated) {
      this.error = 'Please login to Parkadda first';
    }
  }

  loadParkingLocations(): void {
    if (!this.isAuthenticated) {
      return;
    }

    this.loading = true;
    this.error = null;

    this.parkaddaService.getParkingList()
      .pipe(takeUntil(this.destroy$))
      .subscribe({
        next: (response) => {
          this.parkingLocations = response.data || [];
          this.filteredParkings = this.parkingLocations;
          this.totalCount = this.parkingLocations.length;
          this.loading = false;
          this.loadOccupancyForAllParkings();
        },
        error: (err) => {
          this.error = err.message || 'Failed to load parking locations';
          this.loading = false;
        }
      });
  }

  private loadOccupancyForAllParkings(): void {
    this.parkingLocations.forEach(parking => {
      this.parkaddaService.getParkingOccupancy(parking.parking_table_id)
        .pipe(takeUntil(this.destroy$))
        .subscribe({
          next: (occupancy) => {
            this.occupancyData.set(parking.parking_table_id, occupancy);
          },
          error: (err) => {
            console.error(`Failed to load occupancy for parking ${parking.parking_table_id}`, err);
          }
        });
    });
  }

  getOccupancy(parkingId: number): ParkingOccupancy | undefined {
    return this.occupancyData.get(parkingId);
  }

  selectParking(parking: ParkingLocation): void {
    this.parkaddaService.setSelectedParking(parking);
    this.selectedParkingId = parking.parking_table_id;
  }

  openAddDialog(): void {
    this.selectedParking = null;
    // Logic to open add dialog
  }

  onSearchChange(): void {
    this.filteredParkings = this.searchTerm
      ? this.parkingLocations.filter(p =>
          p.parking_name?.toLowerCase().includes(this.searchTerm.toLowerCase()) ||
          p.location?.toLowerCase().includes(this.searchTerm.toLowerCase())
        )
      : this.parkingLocations;
    this.currentPage = 1;
  }

  onFilterChange(): void {
    this.filterByStatus();
    this.currentPage = 1;
  }

  private filterByStatus(): void {
    if (this.statusFilter === 'all') {
      this.filteredParkings = this.parkingLocations;
    } else if (this.statusFilter === 'active') {
      this.filteredParkings = this.parkingLocations.filter(p => p.status === 'active' || p.active === true);
    } else if (this.statusFilter === 'inactive') {
      this.filteredParkings = this.parkingLocations.filter(p => p.status !== 'active' && p.active !== true);
    }
  }

  editParking(parking: ParkingLocation): void {
    this.selectedParking = parking;
    this.showDetailsModal = true;
  }

  deleteParking(parking: ParkingLocation): void {
    if (confirm(`Delete parking: ${parking.parking_name}?`)) {
      this.showToast('Parking deleted successfully', 'success');
    }
  }

  viewAnalytics(parking: ParkingLocation): void {
    this.selectParking(parking);
    this.router.navigate(['/parkadda/dashboard'], {
      queryParams: { parkingId: parking.parking_table_id }
    });
  }

  viewDetails(parking: ParkingLocation): void {
    this.selectParking(parking);
    this.router.navigate(['/parkadda/dashboard'], {
      queryParams: { parkingId: parking.parking_table_id }
    });
  }

  previousPage(): void {
    if (this.currentPage > 1) {
      this.currentPage--;
    }
  }

  nextPage(): void {
    if (this.currentPage < this.totalPages) {
      this.currentPage++;
    }
  }

  closeDetailsModal(): void {
    this.showDetailsModal = false;
    this.selectedParking = null;
  }

  showToast(message: string, type: 'success' | 'error' | 'info' = 'info'): void {
    this.toasts.push({ message, type });
    setTimeout(() => {
      this.toasts.shift();
    }, 3000);
  }

  getToastIcon(type: string): string {
    switch (type) {
      case 'success':
        return 'fa-check-circle';
      case 'error':
        return 'fa-exclamation-circle';
      case 'info':
        return 'fa-info-circle';
      default:
        return 'fa-info-circle';
    }
  }

  getOccupancyPercentage(parkingId: number): number {
    const occupancy = this.getOccupancy(parkingId);
    return occupancy ? occupancy.occupancy_percentage : 0;
  }

  getOccupancyStatus(percentage: number): string {
    if (percentage < 30) return 'low';
    if (percentage < 70) return 'medium';
    return 'high';
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }
}
